using System.Collections.Immutable;
using System.Linq;
using System.Text;
using Microsoft.CodeAnalysis;
using Microsoft.CodeAnalysis.CSharp.Syntax;
using Microsoft.CodeAnalysis.Text;

[Generator]
public class NetReceivedMessageGenerator : IIncrementalGenerator
{
    public void Initialize(IncrementalGeneratorInitializationContext context)
    {
        var methodDeclarations = context.SyntaxProvider
            .CreateSyntaxProvider(
                predicate: (s, _) => s is MethodDeclarationSyntax m && m.AttributeLists.Count > 0,
                transform: (ctx, _) => GetMethodSymbol(ctx))
            .Where(m => m != null);

        context.RegisterSourceOutput(methodDeclarations.Collect(), Execute);
    }

    private IMethodSymbol GetMethodSymbol(GeneratorSyntaxContext ctx)
    {
        var method = (MethodDeclarationSyntax)ctx.Node;
        foreach (var attrList in method.AttributeLists)
        {
            foreach (var attr in attrList.Attributes)
            {
                var symbol = ctx.SemanticModel.GetSymbolInfo(attr).Symbol;
                if (symbol is IMethodSymbol attrSymbol)
                {
                    if (attrSymbol.ContainingType.ToDisplayString() == "NetReceivedMessageAttribute" ||
                        attrSymbol.ContainingType.Name == "NetReceivedMessageAttribute")
                    {
                        return ctx.SemanticModel.GetDeclaredSymbol(method) as IMethodSymbol;
                    }
                }
                else if (attr.Name.ToString().EndsWith("NetReceivedMessage"))
                {
                    return ctx.SemanticModel.GetDeclaredSymbol(method) as IMethodSymbol;
                }
            }
        }
        return null;
    }

    private void Execute(SourceProductionContext context, ImmutableArray<IMethodSymbol> methods)
    {
        if (methods.IsDefaultOrEmpty)
        {
            return;
        }

        var groupedMethods = methods.GroupBy(m => m.ContainingType, SymbolEqualityComparer.Default);

        foreach (var group in groupedMethods)
        {
            var containingType = (INamedTypeSymbol)group.Key;

            var sb = new StringBuilder();
            sb.AppendLine("// <auto-generated/>");
            sb.AppendLine("using NetPacket;");
            sb.AppendLine("using Google.Protobuf;");
            sb.AppendLine("using System;");
            sb.AppendLine("using System.Collections.Generic;");
            sb.AppendLine();

            // 네임스페이스 및 유동적 들여쓰기 제거
            sb.AppendLine($"public static partial class {containingType.Name}");
            sb.AppendLine("{");
            sb.AppendLine("    private static readonly Dictionary<PacketType, Action<IMessage>> _handlers = new()");
            sb.AppendLine("    {");

            foreach (var method in group)
            {
                var attr = method.GetAttributes().FirstOrDefault(a => a.AttributeClass?.Name == "NetReceivedMessageAttribute");
                if (attr == null) continue;

                var packetTypeArg = attr.ConstructorArguments[0];
                var packetTypeName = packetTypeArg.Value?.ToString();

                if (packetTypeArg.Type?.TypeKind == TypeKind.Enum)
                {
                    var enumType = (INamedTypeSymbol)packetTypeArg.Type;
                    var field = enumType.GetMembers().OfType<IFieldSymbol>().FirstOrDefault(f => f.ConstantValue?.Equals(packetTypeArg.Value) == true);
                    if (field != null) packetTypeName = field.Name;
                }

                var paramType = method.Parameters[0].Type.ToDisplayString();
                var handlerName = method.Name;

                sb.AppendLine($"        {{ PacketType.{packetTypeName}, (msg) => {handlerName}(({paramType})msg) }},");
            }

            sb.AppendLine("    };");
            sb.AppendLine();
            sb.AppendLine("    public static partial void Dispatch(PacketHeader header, IMessage payload)");
            sb.AppendLine("    {");
            sb.AppendLine("        if (payload != null && _handlers.TryGetValue(header.TypeId, out var handler))");
            sb.AppendLine("        {");
            sb.AppendLine("            handler(payload);");
            sb.AppendLine("        }");
            sb.AppendLine("    }");
            sb.AppendLine("}");

            var fileName = $"{containingType.Name}_NetReceivedMessage.g.cs";
            context.AddSource(fileName, SourceText.From(sb.ToString(), Encoding.UTF8));
        }
    }
}